64	function luhnCheck(num: string): boolean {
65	  const digits = num.split('').reverse().map(Number);
66	  const sum = digits.reduce((acc, d, i) => {
67	    if (i % 2 === 1) {
68	      const doubled = d * 2;
69	      return acc + (doubled > 9 ? doubled - 9 : doubled);
70	    }
71	    return acc + d;
72	  }, 0);
73	  return sum % 10 === 0;
74	}
