76	function validateForm(form: FormState): FormErrors {
77	  const errors: FormErrors = {};
78	
79	  if (!form.email) {
80	    errors.email = 'Email is required';
81	  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
82	    errors.email = 'Enter a valid email address';
83	  }
84	
85	  if (!form.address.trim()) errors.address = 'Address is required';
86	  if (!form.city.trim()) errors.city = 'City is required';
87	  if (!form.zip.trim()) errors.zip = 'Postcode is required';
88	
89	  const rawCard = form.cardNumber.replace(/\s/g, '');
90	  if (!rawCard) {
91	    errors.cardNumber = 'Card number is required';
92	  } else if (rawCard.length !== 16 || !luhnCheck(rawCard)) {
93	    errors.cardNumber = 'Enter a valid card number';
94	  }
95	
96	  if (!form.cardName.trim()) {
97	    errors.cardName = 'Cardholder name is required';
98	  }
99	
100	  if (!form.cardExpiry) {
101	    errors.cardExpiry = 'Expiry date is required';
102	  } else {
103	    const parts = form.cardExpiry.split('/');
104	    if (parts.length === 2 && parts[0] && parts[1]) {
105	      const month = parseInt(parts[0], 10);
106	      const year = parseInt(parts[1], 10) + 2000;
107	      const now = new Date();
108	      const expDate = new Date(year, month - 1);
109	      if (month < 1 || month > 12 || expDate < new Date(now.getFullYear(), now.getMonth())) {
110	        errors.cardExpiry = 'Enter a valid expiry date';
111	      }
112	    } else {
113	      errors.cardExpiry = 'Enter a valid expiry date';
114	    }
115	  }
116	
117	  if (!form.cardCvv) {
118	    errors.cardCvv = 'CVV is required';
119	  } else if (!/^\d{3,4}$/.test(form.cardCvv)) {
120	    errors.cardCvv = 'Enter a valid CVV';
121	  }
122	
123	  return errors;
124	}
