  city: string;
  state: string;
  zip: string;
  cardNumber: string;
  cardName: string;
  cardExpiry: string;
  cardCvv: string;
};

type FormErrors = Partial<Record<keyof FormState, string>>;
type TouchedFields = Partial<Record<keyof FormState, boolean>>;

type CartState =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: CartData }
  | { status: 'error'; message: string };

type SubmitState =
  | { status: 'idle' }
  | { status: 'loading' }
