import { db } from '../db/db';
import { Database } from 'bun:sqlite';
import { cartItems, shippingFees, purchaseOrders, purchaseOrderItems, products, suppliers } from '../db/schema';

type GeneratedPO = {
  poId: number;
  supplierId: string;
  supplierName: string;
  items: {
    poId: number;
    productSku: string;
    quantity: number;
    total: number;
    productName: string;
    productType: string;
  }[];
  itemTotal: number;
  shippingFee: number;
  orderTotal: number;
  currency: string;
  symbol: string;
};

// Returns null when the cart is empty (already checked out or never populated).
export function processCheckout(): GeneratedPO[] | null {
  // Access the underlying bun:sqlite instance for native transaction support.
  const sqlite = (db as unknown as { session: { db: Database } }).session?.db
