  ConfirmationState,
} from '../types/api';
import { appendSessionOrder } from '../lib/sessionOrders';

type FormState = {
  email: string;
  newsletter: boolean;
  country: string;
  firstName: string;
  lastName: string;
  address: string;
  apartment: string;
  city: string;
  state: string;
  zip: string;
  cardNumber: string;
  cardName: string;
  cardExpiry: string;
  cardCvv: string;
};

type FormErrors = Partial<Record<keyof FormState, string>>;
type TouchedFields = Partial<Record<keyof FormState, boolean>>;

type CartState =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: CartData }
  | { status: 'error'; message: string };

type SubmitState =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'error'; message: string };

const INITIAL_FORM: FormState = {
  email: '',
  newsletter: false,
  country: 'NZ',
  firstName: '',
  lastName: '',
  address: '',
  apartment: '',
  city: '',
  state: '',
  zip: '',
  cardNumber: '',
  cardName: '',
  cardExpiry: '',
  cardCvv: '',
};

function luhnCheck(num: string): boolean {
  const digits = num.split('').reverse().map(Number);
  const sum = digits.reduce((acc, d, i) => {
    if (i % 2 === 1) {
      const doubled = d * 2;
      return acc + (doubled > 9 ? doubled - 9 : doubled);
    }
    return acc + d;
  }, 0);
  return sum % 10 === 0;
}

function validateForm(form: FormState): FormErrors {
  const errors: FormErrors = {};

  if (!form.email) {
    errors.email = 'Email is required';
  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
    errors.email = 'Enter a valid email address';
  }

  if (!form.address.trim()) errors.address = 'Address is required';
  if (!form.city.trim()) errors.city = 'City is required';
  if (!form.zip.trim()) errors.zip = 'Postcode is required';

  const rawCard = form.cardNumber.replace(/\s/g, '');
  if (!rawCard) {
    errors.cardNumber = 'Card number is required';
  } else if (rawCard.length !== 16 || !luhnCheck(rawCard)) {
    errors.cardNumber = 'Enter a valid card number';
  }

  if (!form.cardName.trim()) {
    errors.cardName = 'Cardholder name is required';
  }

  if (!form.cardExpiry) {
    errors.cardExpiry = 'Expiry date is required';
  } else {
    const parts = form.cardExpiry.split('/');
    if (parts.length === 2 && parts[0] && parts[1]) {
      const month = parseInt(parts[0], 10);
      const year = parseInt(parts[1], 10) + 2000;
      const now = new Date();
      const expDate = new Date(year, month - 1);
      if (month < 1 || month > 12 || expDate < new Date(now.getFullYear(), now.getMonth())) {
        errors.cardExpiry = 'Enter a valid expiry date';
      }
    } else {
      errors.cardExpiry = 'Enter a valid expiry date';
    }
  }

  if (!form.cardCvv) {
    errors.cardCvv = 'CVV is required';
  } else if (!/^\d{3,4}$/.test(form.cardCvv)) {
    errors.cardCvv = 'Enter a valid CVV';
  }

  return errors;
}

