1	import React from 'react';
2	import { useNavigate } from 'react-router-dom';
3	import type {
4	  CartResponse,
5	  CartErrorResponse,
6	  CartData,
7	  CheckoutResponse,
8	  CheckoutErrorResponse,
9	  ShippingAddress,
10	  ConfirmationState,
11	} from '../types/api';
12	import { appendSessionOrder } from '../lib/sessionOrders';
13	
14	type FormState = {
15	  email: string;
16	  newsletter: boolean;
17	  country: string;
18	  firstName: string;
19	  lastName: string;
20	  address: string;
21	  apartment: string;
22	  city: string;
23	  state: string;
24	  zip: string;
25	  cardNumber: string;
26	  cardName: string;
27	  cardExpiry: string;
28	  cardCvv: string;
29	};
30	
31	type FormErrors = Partial<Record<keyof FormState, string>>;
32	type TouchedFields = Partial<Record<keyof FormState, boolean>>;
33	
34	type CartState =
35	  | { status: 'idle' }
36	  | { status: 'loading' }
37	  | { status: 'success'; data: CartData }
38	  | { status: 'error'; message: string };
39	
40	type SubmitState =
41	  | { status: 'idle' }
42	  | { status: 'loading' }
43	  | { status: 'error'; message: string };
44	
45	const INITIAL_FORM: FormState = {
46	  email: '',
47	  newsletter: false,
48	  country: 'NZ',
49	  firstName: '',
50	  lastName: '',
51	  address: '',
52	  apartment: '',
53	  city: '',
54	  state: '',
55	  zip: '',
56	  cardNumber: '',
57	  cardName: '',
58	  cardExpiry: '',
59	  cardCvv: '',
60	};
61	
62	function luhnCheck(num: string): boolean {
63	  const digits = num.split('').reverse().map(Number);
64	  const sum = digits.reduce((acc, d, i) => {
65	    if (i % 2 === 1) {
66	      const doubled = d * 2;
67	      return acc + (doubled > 9 ? doubled - 9 : doubled);
68	    }
69	    return acc + d;
70	  }, 0);
71	  return sum % 10 === 0;
72	}
73	
74	function validateForm(form: FormState): FormErrors {
75	  const errors: FormErrors = {};
76	
77	  if (!form.email) {
78	    errors.email = 'Email is required';
79	  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
80	    errors.email = 'Enter a valid email address';
81	  }
82	
83	  if (!form.address.trim()) errors.address = 'Address is required';
84	  if (!form.city.trim()) errors.city = 'City is required';
85	  if (!form.zip.trim()) errors.zip = 'Postcode is required';
86	
87	  const rawCard = form.cardNumber.replace(/\s/g, '');
88	  if (!rawCard) {
89	    errors.cardNumber = 'Card number is required';
90	  } else if (rawCard.length !== 16 || !luhnCheck(rawCard)) {
91	    errors.cardNumber = 'Enter a valid card number';
92	  }
93	
94	  if (!form.cardName.trim()) {
95	    errors.cardName = 'Cardholder name is required';
96	  }
97	
98	  if (!form.cardExpiry) {
99	    errors.cardExpiry = 'Expiry date is required';
100	  } else {
101	    const parts = form.cardExpiry.split('/');
102	    if (parts.length === 2 && parts[0] && parts[1]) {
103	      const month = parseInt(parts[0], 10);
104	      const year = parseInt(parts[1], 10) + 2000;
105	      const now = new Date();
106	      const expDate = new Date(year, month - 1);
107	      if (month < 1 || month > 12 || expDate < new Date(now.getFullYear(), now.getMonth())) {
108	        errors.cardExpiry = 'Enter a valid expiry date';
109	      }
110	    } else {
111	      errors.cardExpiry = 'Enter a valid expiry date';
112	    }
113	  }
114	
115	  if (!form.cardCvv) {
116	    errors.cardCvv = 'CVV is required';
117	  } else if (!/^\d{3,4}$/.test(form.cardCvv)) {
118	    errors.cardCvv = 'Enter a valid CVV';
119	  }
120	
121	  return errors;
122	}
123	
124	// Label floats above by default; peer-placeholder-shown pulls it down when input is empty
125	const LABEL_CLASS =
126	  'absolute left-0 -top-4 text-xs text-outline font-label pointer-events-none ' +
127	  'peer-placeholder-shown:top-3 peer-placeholder-shown:text-base ' +
128	  'peer-focus:-top-4 peer-focus:text-xs peer-focus:text-primary ' +
129	  'transition-all duration-200';
130	
131	const INPUT_CLASS =
132	  'w-full bg-transparent border-0 border-b border-outline-variant/20 ' +
133	  'focus:border-primary focus:ring-0 text-on-surface px-0 py-3 ' +
134	  'peer transition-colors placeholder-transparent';
135	
136	export default function Checkout() {
137	  const navigate = useNavigate();
138	  const [cartState, setCartState] = React.useState<CartState>({ status: 'idle' });
139	  const [submitState, setSubmitState] = React.useState<SubmitState>({ status: 'idle' });
